package ru.memearena.scout.domain; import jakarta.persistence.*; import java.time.*; import java.util.*; @Entity @Table(name="scout_point_event") public class ScoutPointEvent{ @Id private UUID id; @Column(name="user_id") private UUID userId; @Column(name="prediction_id") private UUID predictionId; private int points; @Column(name="event_type") private String eventType; @Column(name="created_at") private Instant createdAt; protected ScoutPointEvent(){} public ScoutPointEvent(UUID id,UUID userId,UUID predictionId,int points,String type,Instant now){this.id=id;this.userId=userId;this.predictionId=predictionId;this.points=points;this.eventType=type;this.createdAt=now;} }
